import type { WithRef } from '@andes/common';
import type { FunctionComponent, ReactNode } from 'react';

type ProgressCircularDeprecatedColors = 'blue' | 'white';

type ProgressIndicatorCircularProps = WithRef<HTMLDivElement> & {
  children?: ReactNode;

  /**
   * Add custom class.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/progress-indicator-circular#props | Documentation}
   */
  className?: string;

  /**
   * Component fill color.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/progress-indicator-circular#props | Documentation}
   * @default 'basic'
   */
  color?: ProgressCircularDeprecatedColors | 'basic' | 'inverse';

  /**
   * Label that describes the ProgressIndicatorCircular's contents.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/progress-indicator-circular#props | Documentation}
   */
  label?: string;

  /**
   * Alignment of the ProgressIndicatorCircular on the screen.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/progress-indicator-circular#props | Documentation}
   */
  modifier?: 'block' | 'fullscreen' | 'inline';

  /**
   * Component size.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/progress-indicator-circular#props | Documentation}
   * @default 'medium'
   */
  size?: 'large' | 'medium' | 'small' | 'xlarge' | 'xsmall';

  /**
   * Sr-only label that allows to notificate changes on the progress for screen reader users.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/progress-indicator-circular#props | Documentation}
   */
  srAnnouncement?: string;

  /**
   * Label that describes the ProgressIndicatorCircular's contents for screen readers.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/progress-indicator-circular#props | Documentation}
   */
  srLabel?: string;

  /**
   * Component variant type.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/progress-indicator-circular#props | Documentation}
   * @default 'indeterminate'
   */
  type?: 'determinate' | 'indeterminate';
};

// Determinate ProgressIndicatorCircular variant-specific properties
type DeterminateSpecificProps = {
  /**
   * You can set `true` if your value is going to change continuously. Otherwise, if your progress value is going to change in a more "stepped" way, you can let this prop as false.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/progress-indicator-circular#props | Documentation}
   */
  continuous?: boolean;

  /**
   * Unique identifier.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/progress-indicator-circular#props | Documentation}
   */
  id?: string;

  /**
   * Shows the percentage progress of the element, it can be between `0` and `100`
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/progress-indicator-circular#props | Documentation}
   */
  value?: number;
};

// Internal used props
type VariantsCommonProps = {
  /**
   * Unique identifier for label.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/progress-indicator-circular#props | Documentation}
   */
  labelId?: string;

  /**
   * Label that describes the ProgressIndicatorCircular's contents for screen readers.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/progress-indicator-circular#props | Documentation}
   */
  srLabel?: string;
};

/**
 * ProgressIndicatorCircular indicates to the user that a process is in progress.
 *
 * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/progress-indicator-circular | Documentation}
 * @see {@link https://andes.mercadolibre.com/924dc6ec5/p/7146d3-progress-indicator/b/26f535 | UI Specs}
 * @example
 * import { ProgressIndicatorCircular } from '@andes/progress-indicator-circular';
 *
 * <ProgressIndicatorCircular
 *  id="my-progress-indicator"
 *  srLabel="Carga en proceso"
 * />
 */
export const ProgressIndicatorCircular: FunctionComponent<
  DeterminateSpecificProps & ProgressIndicatorCircularProps
>;

export type DeterminateProps = DeterminateSpecificProps & VariantsCommonProps;
export type IndeterminateProps = VariantsCommonProps;
